def min_operations_to_portal(n, m, grid):
    min_operations = float('inf')

    # Iterate over all possible top-left corners of the sub-rectangle
    for i in range(n):
        for j in range(m):
            # Iterate over all possible sizes of the sub-rectangle
            for a in range(5, n - i + 1):
                for b in range(4, m - j + 1):
                    # Calculate the cost to make the sub-rectangle a portal
                    operations = 0

                    # Check the borders
                    for x in range(i, i + a):
                        if x == i or x == i + a - 1:
                            # Top or bottom row
                            for y in range(j + 1, j + b - 1):
                                if grid[x][y] != '1':
                                    operations += 1
                        else:
                            # Middle rows
                            if grid[x][j] != '1':
                                operations += 1
                            if grid[x][j + b - 1] != '1':
                                operations += 1

                    # Check the interior
                    for x in range(i + 1, i + a - 1):
                        for y in range(j + 1, j + b - 1):
                            if grid[x][y] != '0':
                                operations += 1

                    # Update the minimum operations
                    min_operations = min(min_operations, operations)

    return min_operations

