MOD = 1000000007

def modinv(a, p):
    return pow(a, p - 2, p)

def precompute_factorials_and_inverses(max_n, mod):
    fact = [1] * (2 * max_n + 1)
    inv_fact = [1] * (2 * max_n + 1)

    for i in range(2, 2 * max_n + 1):
        fact[i] = fact[i - 1] * i % mod

    inv_fact[2 * max_n] = modinv(fact[2 * max_n], mod)
    for i in range(2 * max_n - 1, 0, -1):
        inv_fact[i] = inv_fact[i + 1] * (i + 1) % mod

    return fact, inv_fact

def binomial_coefficient(n, k, fact, inv_fact, mod):
    if k > n or k < 0:
        return 0
    return fact[n] * inv_fact[k] % mod * inv_fact[n - k] % mod

def precompute_valid_permutations(max_n, mod):
    fact, inv_fact = precompute_factorials_and_inverses(max_n, mod)
    valid_permutations = [0] * (max_n + 1)

    for n in range(1, max_n + 1):
        valid_permutations[n] = binomial_coefficient(2 * n, n, fact, inv_fact, mod) * fact[n] % mod

    return valid_permutations

